import { useState } from "react";
import { NavBarRecepcionar } from "./NavBarRecepcionar";
import { Footer } from "./Footer";
import pattern from "../slike/pattern4.jpg";
import axios from "axios";

export function DodajSobu() {
  const [brojSobe, setBrojSobe] = useState("");
  const [sprat, setSprat] = useState("");
  const [tipSobe, setTipSobe] = useState(""); // ovo ce biti checkbox ili select
  const [dostupna, setDostupna] = useState(false);
  const [slika, setSlika] = useState(null);

  const handleFileChange = (e) => {
    setSlika(e.target.files[0]);
  };

  const handleSubmit = async (e) => {
    e.preventDefault();

    if (!brojSobe || !sprat || !tipSobe) {
      alert("Molimo popunite sve podatke!");
      return;
    }

    const formData = new FormData();
    formData.append("file", slika);
    formData.append("soba", new Blob([JSON.stringify({
      brojSobe: brojSobe,
      sprat: sprat,
      tipSobe: { idTipSobe: tipSobe },
      dostupna: dostupna
    })], { type: "application/json" }));

    try {
      const response = await axios.post("http://localhost:8080/rooms/add", formData, {
        headers: {
          "Content-Type": "multipart/form-data"
        }
      });
      alert(response.data);
      // reset forme
      setBrojSobe("");
      setSprat("");
      setTipSobe("");
      setDostupna(false);
      setSlika(null);
    } catch (error) {
      console.error(error);
      alert("Greška pri dodavanju sobe");
    }
  };

  return (
    <div style={{
      minHeight: "100vh",
      display: "flex",
      flexDirection: "column",
      justifyContent: "space-between"
    }}>
      <NavBarRecepcionar />

      <div style={{
        flex: 1,
        backgroundImage: `url(${pattern})`,
        backgroundSize: "cover",
        backgroundPosition: "center",
        display: "flex",
        justifyContent: "center",
        alignItems: "center",
      }}>
        <form 
          onSubmit={handleSubmit}
          style={{
            background: "rgba(255,255,255,0.9)",
            padding: "30px",
            borderRadius: "10px",
            display: "flex",
            flexDirection: "column",
            gap: "15px",
            width: "300px"
          }}
        >
          <h2 style={{ textAlign: "center" }}>Dodaj novu sobu</h2>

          <input
            type="number"
            placeholder="Broj sobe"
            value={brojSobe}
            onChange={(e) => setBrojSobe(e.target.value)}
            required
          />

          <input
            type="number"
            placeholder="Sprat"
            value={sprat}
            onChange={(e) => setSprat(e.target.value)}
            required
          />

          {/* Tip sobe - može biti radio ili select */}
          <select value={tipSobe} onChange={(e) => setTipSobe(e.target.value)} required>
            <option value="">Izaberite tip sobe</option>
            <option value="1">Standard</option>
            <option value="2">Deluxe</option>
            <option value="3">Suite</option>
          </select>

          {/* Dostupna checkbox */}
          <label style={{ display: "flex", alignItems: "center", gap: "5px" }}>
            <input 
              type="checkbox" 
              checked={dostupna} 
              onChange={(e) => setDostupna(e.target.checked)} 
            />
            Dostupna odmah
          </label>

          {/* Upload slike */}
          <input type="file" accept="image/*" onChange={handleFileChange} />

          <button type="submit" className="btnNav">Dodaj sobu</button>
        </form>
      </div>

      <Footer />
    </div>
  );
}
